// Feeds aimed at data-center LITIGATION across the five tracker categories
// (nuisance/noise, water, zoning, environmental, utility). Google News RSS is
// the backbone; a CourtListener RECAP feed adds newly-filed FEDERAL dockets.
// Texas-first, but national landmark filings are wanted too (flagged later).
const DQ = String.fromCharCode(34);
const DC = DQ + 'data center' + DQ;
const NEWS = [
  'Texas ' + DC + ' (lawsuit OR sued OR complaint OR nuisance OR injunction)',
  'Texas (' + DC + ' OR ' + DQ + 'bitcoin mine' + DQ + ' OR ' + DQ + 'crypto mine' + DQ + ') (noise OR nuisance) (lawsuit OR sued OR petition)',
  DC + ' (ratepayer OR ' + DQ + 'public utility commission' + DQ + ' OR PUC OR tariff OR ' + DQ + 'cost allocation' + DQ + ' OR interconnection) (lawsuit OR appeal OR complaint OR petition)',
  DC + ' (groundwater OR water OR well OR ' + DQ + 'water rights' + DQ + ') (lawsuit OR sued OR petition OR permit)',
  '(' + DC + ' OR ' + DQ + 'data centers' + DQ + ') (zoning OR moratorium OR ' + DQ + 'special use' + DQ + ') (lawsuit OR sued OR takings OR appeal)',
  DC + ' (' + DQ + 'clean air act' + DQ + ' OR TCEQ OR emissions OR permit) (lawsuit OR sued OR ' + DQ + 'citizen suit' + DQ + ' OR NAACP)'
];
const feeds = NEWS.map(q => ({ json: { url: 'https://news.google.com/rss/search?q=' + encodeURIComponent(q) + '&hl=en-US&gl=US&ceid=US:en', query: q } }));
// CourtListener RECAP (newly-filed federal dockets). Best-effort: if the feed
// URL ever changes, the RSS node is set to continue on error, so it just yields
// nothing and the news feeds still run.
const CL = [ '"data center" nuisance', '"data center" clean air act' ];
for (const q of CL) {
  feeds.push({ json: { url: 'https://www.courtlistener.com/feed/search/?q=' + encodeURIComponent(q) + '&type=r&order_by=dateFiled+desc', query: 'CourtListener: ' + q } });
}
return feeds;

// Collect RSS articles into one numbered text block + a lookup list so the
// filter sees all headlines at once and cites each by index (real link mapped
// back later by sourceIndex — no URL hallucination).
const items = $input.all();
const headlines = [];
for (const it of items) {
  const j = it.json || {};
  const title = String(j.title || '').trim();
  if (!title) continue;
  const url = String(j.link || j.guid || '').trim();
  const snippet = String(j.contentSnippet || j.content || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 280);
  let source = String(j.creator || '').trim();
  if (!source && title.includes(' - ')) source = title.split(' - ').pop().trim();
  headlines.push({ i: headlines.length, title, snippet, url, source });
}
const text = headlines.map(h => h.i + ') ' + h.title + (h.snippet ? ' \u2014 ' + h.snippet : '')).join('\n');
return [{ json: { headlines, text } }];

