// Turn the filtered leads into a single email digest. Maps each lead back to its
// real source URL by sourceIndex. Writes NO tracker entries — leads only. Texas
// leads are listed first. Category is shown so you know which section it feeds.
const resp = $json;
let text = '';
try { text = resp.candidates[0].content.parts[0].text || ''; } catch (e) { text = ''; }
text = text.trim().replace(/^```(json)?/i, '').replace(/```$/, '').trim();
let leads = [];
try { leads = JSON.parse(text); } catch (e) {
  const m = text.match(/\[([\s\S]*)\]/);
  if (m) { try { leads = JSON.parse(m[0]); } catch (e2) { leads = []; } }
}
if (!Array.isArray(leads)) leads = [];
const headlines = $('Collect headlines').first().json.headlines || [];

leads.sort((a, b) => (b.texas === true ? 1 : 0) - (a.texas === true ? 1 : 0));
const rows = leads.map(l => {
  const src = headlines[l.sourceIndex] || {};
  const url = (src.url && /^https?:\/\//i.test(src.url)) ? src.url : '';
  if (!url) return '';
  const cat = String(l.category || 'case');
  const scope = l.texas === true ? 'TX' : 'national';
  const cap = l.caption ? ' <em>' + l.caption + '</em>' : '';
  return '<li style="margin-bottom:12px"><strong>[' + cat + ' \u00b7 ' + scope + ']</strong>' + cap + ' ' + (src.title || '') + '<br><span style="color:#555">' + (l.why || '') + '</span><br><a href="' + url + '">' + (src.source || 'source') + ' &raquo;</a></li>';
}).filter(Boolean);

const date = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
let html;
if (rows.length === 0) {
  html = '<h2>Litigation radar \u2014 ' + date + '</h2><p>No new data-center litigation leads this week.</p>';
} else {
  html = '<h2>Litigation radar \u2014 ' + date + '</h2><p>' + rows.length + ' possible lead(s). These are LEADS ONLY \u2014 verify each against the actual court/agency docket before publishing. Curate a /litigation entry only from matters you can confirm: copy <code>src/content/litigation/_example.json</code>, describe only what the filing ASSERTS, cite a public sourceUrl, and never call a party liable before a court rules.</p><ul style="padding-left:18px">' + rows.join('') + '</ul>';
}
return [{ json: { emailBodyHtml: html, leadCount: rows.length } }];
